class Solution {
public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        int maxTime = 0;
        int hardestWorkerId = 0;
        int prevEndTime = 0;

        for (const auto& log : logs) {
            int duration = log[1] - prevEndTime;
            prevEndTime = log[1];

            if (duration > maxTime) {
                maxTime = duration;
                hardestWorkerId = log[0];
            } else if (duration == maxTime) {
                hardestWorkerId = min(hardestWorkerId, log[0]);
            }
        }

        return hardestWorkerId;
    }
};
```
